Phase 1: Foundation — Claude Code Build Prompt
Project: corijonesdesign.com — Personal portfolio for a VP of Product Design Stack: Next.js 14+ (App Router), TypeScript, Tailwind CSS, Framer Motion Deploy: Vercel
What to Build
Scaffold a Next.js project with a complete design system foundation. When this phase is done, I should have:
1. A running Next.js app with TypeScript and Tailwind
2. All design tokens as CSS custom properties
3. Fonts loaded and configured (Space Grotesk, Inter, JetBrains Mono)
4. A 12-column grid system component with visible grid overlay (toggle-able)
5. Dark/light theme with smooth toggle
6. Basic responsive layout working across breakpoints
7. A placeholder landing page that demonstrates the type scale, grid, colors, and theme toggle
This is the skeleton everything else builds on. Get this right.
Step 1: Project Setup

```bash
npx create-next-app@latest corijonesdesign --typescript --tailwind --app --src-dir --use-npm
cd corijonesdesign
npm install framer-motion next-themes

```

Step 2: Design Tokens
Create `src/styles/globals.css` with CSS custom properties. These are the source of truth for the entire design system.

```css
@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    /* === DARK MODE (Default) === */
    --bg-primary:        #0A0A0B;
    --bg-secondary:      #141416;
    --bg-elevated:       #1C1C1F;
    --bg-grid:           #1A1A1D;

    --text-primary:      #F0EDE8;
    --text-secondary:    #8A8A8E;
    --text-tertiary:     #4A4A4E;

    --accent:            #E84D1A;
    --accent-hover:      #FF6634;
    --accent-muted:      rgba(232, 77, 26, 0.1);
    --accent-glow:       rgba(232, 77, 26, 0.2);

    --border:            #2A2A2E;
    --border-accent:     rgba(232, 77, 26, 0.27);

    /* === Spacing === */
    --grid-columns:      12;
    --grid-gutter:       1.5rem;
    --grid-margin:       2rem;

    /* === Motion === */
    --ease-out:          cubic-bezier(0.16, 1, 0.3, 1);
    --ease-in-out:       cubic-bezier(0.65, 0, 0.35, 1);
    --duration-fast:     200ms;
    --duration-base:     350ms;
    --duration-slow:     500ms;
    --duration-dramatic: 1200ms;
  }

  [data-theme="light"] {
    --bg-primary:        #F5F2ED;
    --bg-secondary:      #ECEAE5;
    --bg-elevated:       #E3E0DB;
    --bg-grid:           #DDD9D4;

    --text-primary:      #1A1A1D;
    --text-secondary:    #6A6A6E;
    --text-tertiary:     #9A9A9E;

    --accent:            #C93D0E;
    --accent-hover:      #E84D1A;
    --accent-muted:      rgba(201, 61, 14, 0.08);
    --accent-glow:       rgba(201, 61, 14, 0.15);

    --border:            #D0CCC7;
    --border-accent:     rgba(201, 61, 14, 0.2);
  }

  /* === Base Styles === */
  body {
    background-color: var(--bg-primary);
    color: var(--text-primary);
    transition: background-color var(--duration-slow) var(--ease-out),
                color var(--duration-slow) var(--ease-out);
  }

  ::selection {
    background-color: var(--accent-muted);
    color: var(--accent);
  }

  /* === Reduced Motion === */
  @media (prefers-reduced-motion: reduce) {
    *, *::before, *::after {
      animation-duration: 0.01ms !important;
      animation-iteration-count: 1 !important;
      transition-duration: 0.01ms !important;
    }
  }
}

/* === Responsive Grid Margins === */
@media (max-width: 768px) {
  :root {
    --grid-columns: 4;
    --grid-gutter: 1rem;
    --grid-margin: 1rem;
  }
}

@media (min-width: 769px) and (max-width: 1024px) {
  :root {
    --grid-columns: 8;
    --grid-gutter: 1.25rem;
    --grid-margin: 1.5rem;
  }
}

```

Step 3: Tailwind Config
Extend `tailwind.config.ts` to use the design tokens:

```ts
import type { Config } from "tailwindcss";

const config: Config = {
  content: [
    "./src/pages/**/*.{js,ts,jsx,tsx,mdx}",
    "./src/components/**/*.{js,ts,jsx,tsx,mdx}",
    "./src/app/**/*.{js,ts,jsx,tsx,mdx}",
  ],
  theme: {
    extend: {
      colors: {
        bg: {
          primary: "var(--bg-primary)",
          secondary: "var(--bg-secondary)",
          elevated: "var(--bg-elevated)",
          grid: "var(--bg-grid)",
        },
        text: {
          primary: "var(--text-primary)",
          secondary: "var(--text-secondary)",
          tertiary: "var(--text-tertiary)",
        },
        accent: {
          DEFAULT: "var(--accent)",
          hover: "var(--accent-hover)",
          muted: "var(--accent-muted)",
          glow: "var(--accent-glow)",
        },
        border: {
          DEFAULT: "var(--border)",
          accent: "var(--border-accent)",
        },
      },
      fontFamily: {
        display: ["var(--font-space-grotesk)", "system-ui", "sans-serif"],
        body: ["var(--font-inter)", "system-ui", "sans-serif"],
        mono: ["var(--font-jetbrains)", "monospace"],
      },
      fontSize: {
        // Display scale — dramatic
        "display-xl": ["clamp(3.5rem, 8vw, 9rem)", { lineHeight: "0.9", letterSpacing: "-0.04em" }],
        "display-lg": ["clamp(2.5rem, 6vw, 6rem)", { lineHeight: "0.92", letterSpacing: "-0.03em" }],
        "display-md": ["clamp(2rem, 4vw, 4rem)", { lineHeight: "0.95", letterSpacing: "-0.025em" }],
        // Heading scale
        "heading-lg": ["clamp(1.5rem, 3vw, 3rem)", { lineHeight: "1.1", letterSpacing: "-0.02em" }],
        "heading-md": ["clamp(1.25rem, 2vw, 2rem)", { lineHeight: "1.15", letterSpacing: "-0.015em" }],
        "heading-sm": ["clamp(1rem, 1.5vw, 1.5rem)", { lineHeight: "1.2", letterSpacing: "-0.01em" }],
        // Body scale
        "body-lg": ["clamp(1rem, 1.2vw, 1.25rem)", { lineHeight: "1.6" }],
        "body-md": ["clamp(0.95rem, 1.1vw, 1.125rem)", { lineHeight: "1.6" }],
        "body-sm": ["clamp(0.85rem, 0.9vw, 0.95rem)", { lineHeight: "1.5" }],
        // Caption / Label
        "caption": ["0.75rem", { lineHeight: "1.4", letterSpacing: "0.08em" }],
      },
      transitionTimingFunction: {
        "out-expo": "var(--ease-out)",
        "in-out-expo": "var(--ease-in-out)",
      },
      screens: {
        sm: "640px",
        md: "768px",
        lg: "1024px",
        xl: "1280px",
        "2xl": "1536px",
      },
    },
  },
  plugins: [],
};

export default config;

```

Step 4: Font Loading
Create `src/lib/fonts.ts`:

```ts
import { Space_Grotesk, Inter, JetBrains_Mono } from "next/font/google";

export const spaceGrotesk = Space_Grotesk({
  subsets: ["latin"],
  variable: "--font-space-grotesk",
  display: "swap",
  weight: ["400", "500", "600", "700"],
});

export const inter = Inter({
  subsets: ["latin"],
  variable: "--font-inter",
  display: "swap",
});

export const jetbrainsMono = JetBrains_Mono({
  subsets: ["latin"],
  variable: "--font-jetbrains",
  display: "swap",
  weight: ["400"],
});

```

In `src/app/layout.tsx`, apply the font variables to the `<html>` element:

```tsx
import type { Metadata } from "next";
import { spaceGrotesk, inter, jetbrainsMono } from "@/lib/fonts";
import { ThemeProvider } from "@/components/theme-provider";
import "./globals.css";

export const metadata: Metadata = {
  title: "Cori Jones — Product Design Leadership",
  description: "VP of Product Design. I build the systems that let great teams do great work.",
};

export default function RootLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <html
      lang="en"
      suppressHydrationWarning
      className={`${spaceGrotesk.variable} ${inter.variable} ${jetbrainsMono.variable}`}
    >
      <body className="font-body bg-bg-primary text-text-primary antialiased">
        <ThemeProvider>
          {children}
        </ThemeProvider>
      </body>
    </html>
  );
}

```

Step 5: Theme Provider
Create `src/components/theme-provider.tsx`:

```tsx
"use client";

import { createContext, useContext, useEffect, useState } from "react";

type Theme = "dark" | "light";

const ThemeContext = createContext<{
  theme: Theme;
  toggleTheme: () => void;
}>({
  theme: "dark",
  toggleTheme: () => {},
});

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [theme, setTheme] = useState<Theme>("dark");

  useEffect(() => {
    const stored = localStorage.getItem("theme") as Theme;
    if (stored) {
      setTheme(stored);
      document.documentElement.setAttribute("data-theme", stored);
    }
  }, []);

  const toggleTheme = () => {
    const next = theme === "dark" ? "light" : "dark";
    setTheme(next);
    localStorage.setItem("theme", next);
    document.documentElement.setAttribute("data-theme", next);
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export const useTheme = () => useContext(ThemeContext);

```

Step 6: Grid System Component
Create `src/components/grid/grid.tsx`:

```tsx
"use client";

import { useState } from "react";

interface GridProps {
  children: React.ReactNode;
  className?: string;
}

export function Grid({ children, className = "" }: GridProps) {
  return (
    <div
      className={`grid grid-cols-4 md:grid-cols-8 lg:grid-cols-12 gap-[var(--grid-gutter)] px-[var(--grid-margin)] mx-auto max-w-[1536px] ${className}`}
    >
      {children}
    </div>
  );
}

// Dev-only: visible grid overlay
export function GridOverlay() {
  const [visible, setVisible] = useState(false);

  if (process.env.NODE_ENV !== "development") return null;

  return (
    <>
      {/* Toggle button */}
      <button
        onClick={() => setVisible(!visible)}
        className="fixed bottom-4 right-4 z-[9999] px-3 py-1.5 text-caption uppercase font-mono bg-bg-elevated text-text-secondary border border-border rounded hover:text-accent transition-colors"
      >
        Grid
      </button>

      {/* Overlay */}
      {visible && (
        <div className="fixed inset-0 z-[9998] pointer-events-none px-[var(--grid-margin)]">
          <div className="grid grid-cols-4 md:grid-cols-8 lg:grid-cols-12 gap-[var(--grid-gutter)] h-full max-w-[1536px] mx-auto">
            {Array.from({ length: 12 }).map((_, i) => (
              <div
                key={i}
                className="h-full bg-accent/[0.04] border-x border-accent/[0.08] hidden lg:block first:block md:first:block [&:nth-child(-n+4)]:block md:[&:nth-child(-n+8)]:block"
              />
            ))}
          </div>
        </div>
      )}
    </>
  );
}

```

Also create `src/components/grid/grid-item.tsx` for placing items on the grid:

```tsx
interface GridItemProps {
  children: React.ReactNode;
  /** Column span on each breakpoint: [mobile, tablet, desktop] */
  span?: [number, number, number];
  /** Column start on each breakpoint: [mobile, tablet, desktop] */
  start?: [number, number, number];
  className?: string;
}

export function GridItem({
  children,
  span = [4, 8, 12],
  start,
  className = "",
}: GridItemProps) {
  const spanClasses = `col-span-${span[0]} md:col-span-${span[1]} lg:col-span-${span[2]}`;
  const startClasses = start
    ? `col-start-${start[0]} md:col-start-${start[1]} lg:col-start-${start[2]}`
    : "";

  return (
    <div className={`${spanClasses} ${startClasses} ${className}`}>
      {children}
    </div>
  );
}

```

Step 7: Theme Toggle Component
Create `src/components/ui/theme-toggle.tsx`:

```tsx
"use client";

import { useTheme } from "@/components/theme-provider";
import { motion } from "framer-motion";

export function ThemeToggle() {
  const { theme, toggleTheme } = useTheme();

  return (
    <button
      onClick={toggleTheme}
      className="fixed top-6 right-6 z-50 w-10 h-10 flex items-center justify-center rounded-full border border-border hover:border-accent transition-colors duration-[var(--duration-base)]"
      aria-label={`Switch to ${theme === "dark" ? "light" : "dark"} mode`}
    >
      <motion.div
        initial={false}
        animate={{ rotate: theme === "dark" ? 0 : 180, scale: 1 }}
        transition={{ duration: 0.5, ease: [0.16, 1, 0.3, 1] }}
      >
        {theme === "dark" ? (
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <circle cx="8" cy="8" r="3.5" stroke="currentColor" strokeWidth="1.5" />
            <path d="M8 1v2M8 13v2M1 8h2M13 8h2M3.05 3.05l1.41 1.41M11.54 11.54l1.41 1.41M3.05 12.95l1.41-1.41M11.54 4.46l1.41-1.41" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
          </svg>
        ) : (
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <path d="M14 8.5A6.5 6.5 0 017.5 2 5.5 5.5 0 1014 8.5z" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        )}
      </motion.div>
    </button>
  );
}

```

