import { Space_Grotesk, Inter, JetBrains_Mono } from "next/font/google";

export const spaceGrotesk = Space_Grotesk({
  subsets: ["latin"],
  variable: "--font-space-grotesk",
  display: "swap",
  weight: ["400", "500", "600", "700"],
});

export const inter = Inter({
  subsets: ["latin"],
  variable: "--font-inter",
  display: "swap",
});

export const jetbrainsMono = JetBrains_Mono({
  subsets: ["latin"],
  variable: "--font-jetbrains",
  display: "swap",
  weight: ["400"],
});

"use client";

import { createContext, useContext, useEffect, useState } from "react";

type Theme = "dark" | "light";

const ThemeContext = createContext<{
  theme: Theme;
  toggleTheme: () => void;
}>({
  theme: "dark",
  toggleTheme: () => {},
});

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [theme, setTheme] = useState<Theme>("dark");
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    const stored = localStorage.getItem("theme") as Theme;
    if (stored) {
      setTheme(stored);
      document.documentElement.setAttribute("data-theme", stored);
    }
  }, []);

  const toggleTheme = () => {
    const next = theme === "dark" ? "light" : "dark";
    setTheme(next);
    localStorage.setItem("theme", next);
    document.documentElement.setAttribute("data-theme", next);
  };

  // Prevent flash of wrong theme
  if (!mounted) {
    return <>{children}</>;
  }

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export const useTheme = () => useContext(ThemeContext);

"use client";

import { useState } from "react";

interface GridProps {
  children: React.ReactNode;
  className?: string;
}

export function Grid({ children, className = "" }: GridProps) {
  return (
    <div
      className={`mx-auto max-w-[1536px] ${className}`}
      style={{
        display: "grid",
        gridTemplateColumns: `repeat(var(--grid-columns), 1fr)`,
        gap: "var(--grid-gutter)",
        paddingLeft: "var(--grid-margin)",
        paddingRight: "var(--grid-margin)",
      }}
    >
      {children}
    </div>
  );
}

// Dev-only: visible grid overlay
export function GridOverlay() {
  const [visible, setVisible] = useState(false);

  return (
    <>
      {/* Toggle button */}
      <button
        onClick={() => setVisible(!visible)}
        className="fixed bottom-4 right-4 z-[9999] cursor-pointer px-3 py-1.5 uppercase font-mono text-[0.75rem] tracking-[0.08em] bg-bg-elevated text-text-secondary border border-border-default rounded hover:text-accent transition-colors"
      >
        Grid
      </button>

      {/* Overlay */}
      {visible && (
        <div
          className="fixed inset-0 z-[9998] pointer-events-none"
          style={{
            paddingLeft: "var(--grid-margin)",
            paddingRight: "var(--grid-margin)",
          }}
        >
          <div
            className="h-full max-w-[1536px] mx-auto"
            style={{
              display: "grid",
              gridTemplateColumns: `repeat(var(--grid-columns), 1fr)`,
              gap: "var(--grid-gutter)",
            }}
          >
            {Array.from({ length: 12 }).map((_, i) => (
              <div
                key={i}
                className="h-full"
                style={{
                  backgroundColor: "rgba(232, 77, 26, 0.04)",
                  borderLeft: "1px solid rgba(232, 77, 26, 0.08)",
                  borderRight: "1px solid rgba(232, 77, 26, 0.08)",
                }}
              />
            ))}
          </div>
        </div>
      )}
    </>
  );
}

interface GridItemProps {
  children: React.ReactNode;
  /** Column span on each breakpoint: [mobile, tablet, desktop] */
  span?: [number, number, number];
  /** Column start on each breakpoint: [mobile, tablet, desktop] */
  start?: [number, number, number];
  className?: string;
}

export function GridItem({
  children,
  span = [4, 8, 12],
  start,
  className = "",
}: GridItemProps) {
  // Use CSS custom properties that respond to breakpoints
  // The grid already changes --grid-columns per breakpoint,
  // so we use inline styles for reliable grid placement
  return (
    <div
      className={`grid-item ${className}`}
      style={{
        gridColumn: start
          ? `${start[2]} / span ${span[2]}`
          : `span ${span[2]}`,
      }}
      data-span-mobile={span[0]}
      data-span-tablet={span[1]}
      data-span-desktop={span[2]}
      data-start-mobile={start?.[0]}
      data-start-tablet={start?.[1]}
      data-start-desktop={start?.[2]}
    >
      {children}
    </div>
  );
}

"use client";

import { useTheme } from "@/components/theme-provider";
import { motion } from "framer-motion";

export function ThemeToggle() {
  const { theme, toggleTheme } = useTheme();

  return (
    <button
      onClick={toggleTheme}
      className="fixed top-6 right-6 z-50 w-10 h-10 flex items-center justify-center rounded-full border border-border-default hover:border-accent transition-colors cursor-pointer"
      style={{ transitionDuration: "var(--duration-base)" }}
      aria-label={`Switch to ${theme === "dark" ? "light" : "dark"} mode`}
    >
      <motion.div
        initial={false}
        animate={{ rotate: theme === "dark" ? 0 : 180, scale: 1 }}
        transition={{ duration: 0.5, ease: [0.16, 1, 0.3, 1] }}
      >
        {theme === "dark" ? (
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <circle cx="8" cy="8" r="3.5" stroke="currentColor" strokeWidth="1.5" />
            <path
              d="M8 1v2M8 13v2M1 8h2M13 8h2M3.05 3.05l1.41 1.41M11.54 11.54l1.41 1.41M3.05 12.95l1.41-1.41M11.54 4.46l1.41-1.41"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
            />
          </svg>
        ) : (
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <path
              d="M14 8.5A6.5 6.5 0 017.5 2 5.5 5.5 0 1014 8.5z"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        )}
      </motion.div>
    </button>
  );
}

